
import React, { useState, useEffect } from "react";



import { CloseModal, OpenModal } from "../../../components/DialogHRM";
import {  TextInput_Cmpt } from "../../../components";
import { updStore, getStore, gen16CodeId, ObjectKeys, parseDateMMYYYY, qryKClient, parseDate, parseDateMMDDYYYY, txtOrempty, compareJSON, fetchEncryptStream, _monthNames, qryStore } from "../../../stores/Utils";

import DateCalComponent from "./DateCalComponent";
import { generateTranslateDriverLicense } from "../services/print_service";
import { get_print_structure } from "../services/customer_fetch_service";



