const TranslateDL  = ({ data,  confirm }) => {
	
	let flds = [
		"dl_number",
		"dl_issues",
		"dl_exire",
		"dl_type",
		"endorsment",
		"restriction",
		"documentType"
	]

	const frmNm = "driver_licence_translate"

	const [initialize, setInitialize] = useState(false);

	const [obs, set_obs] = useState(1);
	
	const updObs =  () => {
		set_obs(gen16CodeId())
	}


	
	useEffect(() => {
		if (!initialize) {
			
			setInitialize(true);
			set_obs(gen16CodeId());
			if(!getStore("print_structure")?.dl_trns_struct_print){
				get_print_structure(updObs)
			}
			updFrm("documentType","DLT");
			return () => {
				// updStore(frmNm, null);
			}; 
		}
	});

	const updFrm = (f, v) => {
		let frm2 = getStore(frmNm) || {};
		frm2[f] = v;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};



	const save  = async ()  => {

		let ffm =  getStore(frmNm);

		let bdyq2 = {};
		if(ffm["caseId"]){
			let diff = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
			
			bdyq2 = {...getStore(qryStore())?.upd_notry_case};
			bdyq2.params = {
				customerId: getStore(qryKClient())?.clientNotaryId,
				"caseId": ffm["caseId"]
			};
			bdyq2.data2update = diff.data;
		}
		else{
			ffm["customerId"] = getStore(qryKClient()).clientNotaryId;
			ffm["documentType"] = "DLT";
			ffm["caseId"] = gen16CodeId();
			
			if(!ffm["date"]){
				ffm["date"] = (new Date()).getTime()+800;
			}
			else{
				ffm["date"] =(new Date(ffm["date"])).getTime();
			}
			
			bdyq2 = {...getStore(qryStore())?.add_notry_case};
			bdyq2.params = {
				customerId: getStore(qryKClient())?.clientNotaryId
			};
			bdyq2.form = ffm;
		}
		// * Class B Automovile (Mar 2010), C: Truck over 7500KG (Jun 2014)
	
		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && !td.error) {
			close();
		}
	}


	const print  = async ()  => {

		let user = {...getStore(qryKClient())};
		let ffm = Object.assign({}, getStore(frmNm),user);

		let fullname =	txtOrempty(user?.firstName) + txtOrempty(user?.middleName) +  txtOrempty(user?.lastName);
		
		if(user?.firstName){
			ffm["name_jury"] = fullname;
			ffm["name"] = fullname;
		}

		if(user["dateOfBirth"]){
			ffm["dob_p"] = parseDateMMDDYYYY(user["dateOfBirth"]);
		}

		if(ffm["dl_issues"]){
			ffm["dl_issue_p"] = parseDateMMYYYY(ffm["dl_issues"]);
		}

		if(ffm["dl_exire"]){
			ffm["dl_exp_p"] = parseDateMMYYYY(ffm["dl_exire"]);
		}

		if(ffm["ss"]){
			ffm["SS"] = parseSS(ffm["ss"]);
		}else{
			ffm["SS"] = "N/A";
		}

		
	
		
		let tDdate = ffm["translateDate"] ? (new Date(ffm["translateDate"]))  : (new Date());

		let DD = tDdate.getDate();
		let YY = tDdate.getFullYear().toString().slice(2,4);



		ffm["inter_date"] =  parseDateMMDDYYYY(tDdate.getTime());



		ffm["day_en_jury"] = DD;
		ffm["day_es_jury"] = DD;
		ffm["half_year_en_jury"] = YY;
		ffm["half_year_es_jury"] = YY;

		let MM = tDdate.getMonth()+1;

		ffm["month_en_jury"] = _monthNames["en"][MM];
		ffm["month_es_jury"] = _monthNames["es"][MM];
		
	
		let pdfUri = await generateTranslateDriverLicense(ffm, true, true);
		window.open(pdfUri);
	};

	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}
	
	let validSv = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
	


	return(
		<div style={{
			maxHeight: "80vh",
			width: "820px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title">
					Traducion de la Licencia
				</p>
				<div className="flexSpace"/>
				<div className="card">
						<GrayButton label={"Imprimir"} clickHandler={print}/>
					
				</div>
			</div>
			
			
			

		
			<div className="_dsplFlx spaceAround flxWrp" style={{margin:"30px 0px 0 0"}}>
				
				<TextInput  init={getStore(frmNm)?.["dl_number"]} 
					label={"Numero de Licencia"} 
					width={160} updChanges={(e)=>updFrm("dl_number",e)}
				/>
				<DateCalComponent  
					init={getStore(frmNm)?.["dl_issues"]} 
					label={"Fecha de emicion"}
					updDate={(e)=>updFrm("dl_issues",e)}
				/>
				<DateCalComponent  
					init={getStore(frmNm)?.["dl_exire"]} 
					label={"Fecha de expiracion"}
					updDate={(e)=>updFrm("dl_exire",e)}
				/>
			</div>
			<div className="_dsplFlx spaceAround flxWrp"> 
				<TextInput  init={getStore(frmNm)?.["dl_type"]} label={"Tipo de Licencia"} width={650} updChanges={(e)=>updFrm("dl_type",e)}/>
				<TextInput  
					init={getStore(frmNm)?.["endorsment"]} 
					label={"Aprobaciónes"} 
					width={650} 
					updChanges={(e)=>updFrm("endorsment",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["restriction"]} 
					label={"Restriciones"} 
					width={650} 
					updChanges={(e)=>updFrm("restriction",e)}
				/>
			</div> 
			
			<div className="_dsplFlx spaceAround" style={{marginTop:20}}>
				<DateCalComponent
					init={getStore(frmNm)?.["translateDate"]} 
					label={"Fecha de la traduccion"}
					updDate={(e)=>updFrm("translateDate",e)}
				/>
			</div>

			<div className="_dsplFlx spaceAround" style={{marginTop:20}}>
		
			{validSv?.hasChange ? (
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={"Actualizar"} clickHandler={save}/>
						
					</div>
				</div>
			):<div className="card"/>}

			</div>
		</div>
	)

}



export default TranslateDL;








const GrayButton  = ({ clickHandler, label }) => {
	return (
		<div className=" jaqJnq_hrm1"  >
			<button className="gHAsFI_hrm1 dqnOfN jUrKkb" onClick={clickHandler}>
				<span className=" jaqJnq_hrm1" >
					{label}
				</span>
			</button>
		</div>
	)
}



const parseSS = (v) =>{
	if(v){
		let f = v.substring(0,3) + " - "+ v.substring(3,5) + " - "+v.substring(5,9);
		return f;
	}
	return ""

}